const body = $('Webhook — Receber CV').first().json.body;
const resumeId = body.resume_id;
const callbackUrl = body.callback_url;
const cvText = (body.cv_text || '').slice(0, 8000);

const prompt = `Analisa o seguinte currículo e responde APENAS com um JSON válido. 
REGRAS OBRIGATÓRIAS:
- Todos os valores devem ser STRINGS de texto simples, nunca objectos ou arrays aninhados
- O campo "skills" deve ser uma LISTA de strings simples: ["Python", "Django", "SQL"]
- Os campos "experience" e "education" devem ser texto corrido em português, NÃO objectos JSON
- O campo "feedback" deve ser um parágrafo de texto, NÃO um objecto
- NÃO uses markdown, código ou blocos de texto adicionais

Estrutura exacta esperada:
{
  "score": <número inteiro 0-100 representando a qualidade geral do CV>,
  "skills": ["competência1", "competência2", "competência3"],
  "summary": "<resumo profissional em 2-3 frases>",
  "experience": "<toda a experiência profissional em texto corrido, separada por ponto e vírgula>",
  "education": "<toda a formação académica em texto corrido>",
  "languages": "<idiomas separados por vírgula>",
  "feedback": "<análise com pontos fortes e sugestões de melhoria em texto corrido>"
}

Currículo a analisar:
${cvText}`;

const requestBody = JSON.stringify({
  model: $env.OLLAMA_MODEL || 'llama3.2:1b',
  stream: false,
  format: 'json',
  prompt: prompt
});

return [{ json: { resume_id: resumeId, callback_url: callbackUrl, requestBody } }];

const ollamaResp = $input.first().json;
const metadata = $('Construir Prompt CV').first().json;

function toStr(val) {
  if (val === null || val === undefined) return '';
  if (typeof val === 'string') return val.trim();
  if (Array.isArray(val)) return val.map(item => typeof item === 'object' ? JSON.stringify(item) : String(item)).join(', ');
  if (typeof val === 'object') {
    const parts = [];
    for (const [k, v] of Object.entries(val)) {
      if (v && typeof v === 'string') parts.push(v);
      else if (v && typeof v === 'object') parts.push(toStr(v));
    }
    return parts.filter(Boolean).join(' | ') || JSON.stringify(val);
  }
  return String(val);
}

let analysis = {};
try {
  const raw = ollamaResp.response || ollamaResp.text || '{}';
  const cleaned = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = {};
}

const score = Math.min(100, Math.max(0, parseFloat(analysis.score) || 50));

const skills = Array.isArray(analysis.skills)
  ? analysis.skills.map(s => typeof s === 'object' ? toStr(s) : String(s)).join(', ')
  : toStr(analysis.skills) || 'Não identificadas';

const summary    = toStr(analysis.summary)    || 'Resumo não disponível';
const experience = toStr(analysis.experience) || 'Não especificada';
const education  = toStr(analysis.education)  || 'Não especificada';
const languages  = toStr(analysis.languages)  || 'Não identificados';
const feedback   = toStr(analysis.feedback)   || 'Análise concluída.';

const requestBody = JSON.stringify({
  score, skills, summary, experience, education, languages, feedback
});

return [{
  json: {
    callback_url: metadata.callback_url,
    resume_id: metadata.resume_id,
    requestBody
  }
}];
